mapper.select:
SELECT account_id, phone, status, last_active_identity_id, last_active_identity_type
FROM t_account
WHERE account_id = #{accountId}

SELECT account_id
FROM t_account_wechat_identity
WHERE mini_program_app_id = #{miniProgramAppId}
  AND subject_hash = #{subjectHash}
LIMIT 1

SELECT account_id, mini_program_app_id, subject_hash, nickname, avatar_url
FROM t_account_wechat_identity
WHERE account_id = #{accountId}
  AND mini_program_app_id = #{miniProgramAppId}
LIMIT 1

mapper.update:
UPDATE t_account_wechat_identity
SET last_login_time = CURRENT_TIMESTAMP,
    update_time = CURRENT_TIMESTAMP
WHERE account_id = #{accountId}
  AND mini_program_app_id = #{miniProgramAppId}

UPDATE t_account_wechat_identity
SET nickname = #{nickname},
    avatar_url = #{avatarUrl},
    update_time = CURRENT_TIMESTAMP
WHERE account_id = #{accountId}
  AND mini_program_app_id = #{miniProgramAppId}
